 1	import React, { FC, useCallback, useState } from 'react';
 2	
 3	import { produceVMDisks } from '@catalog/utils/WizardVMContext';
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
 6	import DiskModal from '@kubevirt-utils/components/DiskModal/DiskModal';
 7	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 8	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 9	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { getContentScrollableElement } from '@kubevirt-utils/utils/utils';
12	import { ButtonVariant, Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
13	
14	type DiskRowActionsProps = {
15	  diskName: string;
16	  isDisabled?: boolean;
17	  onUpdate: (updatedVM: V1VirtualMachine) => Promise<void>;
18	  vm: V1VirtualMachine;
19	};
20	
21	const DiskRowActions: FC<DiskRowActionsProps> = ({ diskName, isDisabled, onUpdate, vm }) => {
22	  const { t } = useKubevirtTranslation();
23	  const { createModal } = useModal();
24	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
25	  const deleteBtnText = t('Detach');
26	
27	  const onDelete = useCallback(() => {
28	    const vmWithDeletedDisk = produceVMDisks(vm, (draftVM) => {
29	      const volumeToDelete = draftVM.spec.template.spec.volumes.find(
30	        (volume) => volume.name === diskName,
31	      );
32	
33	      if (volumeToDelete?.dataVolume?.name) {
34	        draftVM.spec.dataVolumeTemplates = draftVM.spec.dataVolumeTemplates.filter(
35	          (dataVolume) => dataVolume.metadata.name !== volumeToDelete.dataVolume.name,
36	        );
37	      }
38	
39	      draftVM.spec.template.spec.volumes = draftVM.spec.template.spec.volumes.filter(
40	        (volume) => volume.name !== diskName,
41	      );
42	      draftVM.spec.template.spec.domain.devices.disks =
43	        draftVM.spec.template.spec.domain.devices.disks.filter((disk) => disk.name !== diskName);
44	    });
45	
46	    return onUpdate(vmWithDeletedDisk);
47	  }, [diskName, onUpdate, vm]);
48	
49	  const onDeleteModalToggle = () => {
50	    createModal(({ isOpen, onClose }) => (
51	      <TabModal<V1VirtualMachine>
52	        headerText={t('Detach disk?')}
53	        isOpen={isOpen}
54	        obj={vm}
55	        onClose={onClose}
56	        onSubmit={onDelete}
57	        submitBtnText={deleteBtnText}
58	        submitBtnVariant={ButtonVariant.danger}
59	      >
60	        <ConfirmActionMessage action="detach" obj={{ metadata: { name: diskName } }} />
61	      </TabModal>
62	    ));
63	  };
64	
65	  const onEditModalToggle = () => {
66	    createModal(({ isOpen, onClose }) => (
67	      <DiskModal
68	        editDiskName={diskName}
69	        isOpen={isOpen}
70	        onClose={onClose}
71	        onSubmit={onUpdate}
72	        vm={vm}
73	      />
74	    ));
75	  };
76	
77	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
78	
79	  return (
80	    <Dropdown
81	      isOpen={isDropdownOpen}
82	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
83	      onSelect={() => setIsDropdownOpen(false)}
84	      popperProps={{ appendTo: getContentScrollableElement, position: 'right' }}
85	      toggle={KebabToggle({ id: 'toggle-id-disk', isDisabled, onClick: onToggle })}
86	    >
87	      <DropdownList>
88	        <DropdownItem key="disk-edit" onClick={onEditModalToggle}>
89	          {t('Edit')}
90	        </DropdownItem>
91	        <DropdownItem key="disk-delete" onClick={onDeleteModalToggle}>
92	          {deleteBtnText}
93	        </DropdownItem>
94	      </DropdownList>
95	    </Dropdown>
96	  );
97	};
98	
99	export default DiskRowActions;

